import{_ as e,o as l,c as i,ag as r}from"./chunks/framework.DNt_9s2P.js";const q=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),t={name:"guide/faq.md"};function o(h,a,n,d,s,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="全般" tabindex="-1">全般 <a class="header-anchor" href="#全般" aria-label="Permalink to &quot;全般&quot;">​</a></h2><h3 id="selah-は大学公式のアプリですか" tabindex="-1">Selah は大学公式のアプリですか？ <a class="header-anchor" href="#selah-は大学公式のアプリですか" aria-label="Permalink to &quot;Selah は大学公式のアプリですか？&quot;">​</a></h3><p>いいえ。Selah は個人が開発した非公式のデスクトップクライアントです。関西学院大学との提携・承認は一切ありません。</p><h3 id="無料で使えますか" tabindex="-1">無料で使えますか？ <a class="header-anchor" href="#無料で使えますか" aria-label="Permalink to &quot;無料で使えますか？&quot;">​</a></h3><p>はい。Selah はオープンソース (MIT License) で、無料で使用できます。AI 機能を使う場合は、別途 OpenAI / Google の API 利用料がかかります。</p><h3 id="ログイン情報はどこに保存されますか" tabindex="-1">ログイン情報はどこに保存されますか？ <a class="header-anchor" href="#ログイン情報はどこに保存されますか" aria-label="Permalink to &quot;ログイン情報はどこに保存されますか？&quot;">​</a></h3><p>ログイン時の認証情報は macOS の Keychain、Windows の Credential Store に保存されます。アプリのコード内にパスワードが平文で保存されることはありません。</p><h2 id="トラブルシューティング" tabindex="-1">トラブルシューティング <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;トラブルシューティング&quot;">​</a></h2><h3 id="ログインできません" tabindex="-1">ログインできません <a class="header-anchor" href="#ログインできません" aria-label="Permalink to &quot;ログインできません&quot;">​</a></h3><ul><li>利用者 ID とパスワードが正しいか確認してください</li><li>大学の SSO サービスが一時的にダウンしている可能性があります。しばらく時間をおいて再試行してください</li><li>VPN 経由の場合、接続が不安定な場合があります</li></ul><h3 id="データが更新されません" tabindex="-1">データが更新されません <a class="header-anchor" href="#データが更新されません" aria-label="Permalink to &quot;データが更新されません&quot;">​</a></h3><ul><li>インターネット接続を確認してください</li><li>アプリを再起動してみてください</li><li>セッションが切れている場合は、再ログインが必要です</li></ul><h3 id="ai-機能が動作しません" tabindex="-1">AI 機能が動作しません <a class="header-anchor" href="#ai-機能が動作しません" aria-label="Permalink to &quot;AI 機能が動作しません&quot;">​</a></h3><ul><li>設定画面で API キーが正しく入力されているか確認してください</li><li>API キーの利用制限に達していないか、OpenAI / Google のダッシュボードで確認してください</li></ul><h3 id="macos-で「開発元が確認できない」と表示されます" tabindex="-1">macOS で「開発元が確認できない」と表示されます <a class="header-anchor" href="#macos-で「開発元が確認できない」と表示されます" aria-label="Permalink to &quot;macOS で「開発元が確認できない」と表示されます&quot;">​</a></h3><p><strong>システム設定 &gt; プライバシーとセキュリティ</strong> から「このまま開く」を選択してください。</p>',17)])])}const f=e(t,[["render",o]]);export{q as __pageData,f as default};
